ValidationRule.errorConditionFormula:
OR(
	AND(
		ISPICKVAL( General_Ledger_Entry_Type__c , "Credit"),
		ISBLANK(Credit_Entry__c)
	),
	AND(
		ISPICKVAL( General_Ledger_Entry_Type__c , "Debit"),
		ISBLANK(Debit_Entry__c)
	),
	AND(
		ISPICKVAL( General_Ledger_Entry_Type__c , "Credit"),
		NOT ( 
			OR(
				ISNULL( Debit_Entry__c),
				ISBLANK( Debit_Entry__c)
			)
		)

	),
	AND(
		ISPICKVAL( General_Ledger_Entry_Type__c , "Debit"),
		NOT(
			OR(
				ISNULL( Credit_Entry__c),
				ISBLANK( Credit_Entry__c)
			)
		)
	)
)
